{
  "name": "Senior Medicare Patrol (SMP)",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; open to all Medicare beneficiaries, families, and caregivers[1][2][7]",
    "asset_limits": "No asset limits; no financial tests apply[1][2]",
    "other_requirements": ["Must be a Medicare beneficiary, family member, or caregiver in Arkansas; no other restrictions[1][2][7]"]
  },
  "benefits": {
    "type": "service",
    "value": "Outreach and education on Medicare fraud prevention; one-on-one counseling; advocacy to resolve billing disputes; referrals for suspected fraud, errors, or abuse; community presentations and materials; often co-located with SHIP health insurance counseling[1][2][4]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: 1-866-726-2916", "Email: [email protected]", "Website: https://insurance.arkansas.gov/consumer-assistance/senior-medicare-patrol-smp/", "Schedule free speaker or report issues via phone/email[2]"],
    "processing_time": "Immediate assistance for counseling and referrals; no formal application processing[1][2][4]",
    "waitlist": null,
    "forms": ["No specific forms required for receiving services; volunteer applications available via Arkansas Insurance Department website[2][3]"],
    "documents": ["Medicare Summary Notice (MSN) or billing statements if reporting specific issues; no documents needed for general education/outreach[1][6]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; available to all Arkansas Medicare beneficiaries[2]",
    "regional_variations": "Administered statewide by Arkansas Insurance Department; no regional differences noted[2]",
    "offices_or_providers": ["Arkansas Insurance Department (statewide contact); local SMP volunteers conduct services[2]"]
  },
  "official_source": "https://insurance.arkansas.gov/consumer-assistance/senior-medicare-patrol-smp/[2]",
  "gotchas": ["Not a financial assistance or healthcare benefits program—focuses solely on fraud prevention, education, and advocacy; often confused with benefit-paying programs; volunteers handle services, so availability depends on local staffing; many sites also offer SHIP counseling, which is separate[1][2][4]", "No monetary benefits or direct payments; people miss that it's preventive education, not eligibility-based aid[1][7]"],
  "data_shape_notes": "no income test; volunteer-based education and advocacy program; not a benefits entitlement; statewide with phone/email access; co-administered with SHIP in Arkansas[1][2][4]"
}

{
  "name": "Family Caregiver Support Program",
  "eligibility": {
    "age": 60,
    "income_limits": "No income restrictions.[1]",
    "asset_limits": "No asset limits mentioned; not applicable.[1]",
    "other_requirements": ["Care recipient must be at least 60 years old (no age limit if they have Alzheimer's or related dementia).[1]", "Caregiver must assist with activities such as transportation, housework, meal preparation, medication reminders, medical appointments, managing finances, dressing, or managing chronic conditions like diabetes or dementia.[1]", "Contact local Area Agency on Aging for grant-specific requirements, which may include diagnosis, age, or location.[3]"]
  },
  "benefits": {
    "type": "service",
    "value": "Respite grants, counseling, training, and access to assistance services including respite care; specific services and amounts vary by grant (e.g., home care, day care, or facility care, but not duplicating other funding sources).[1][3][5]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Contact local Area Agency on Aging (no specific statewide phone or URL listed; visit agingarkansas.org for details).[1][3]", "For specific grants like CareLink: Apply through Alzheimer's Arkansas Programs and Services, 201 Markham Center Drive, Little Rock AR 72205 (regional).[5]"],
    "processing_time": "Not specified in sources.",
    "waitlist": null,
    "forms": ["Varies by grant; e.g., 4-Step Application Process for CareLink grant (no form number).[5]"],
    "documents": ["Physician certification of chronic illness for some grants (e.g., CareLink); proof care recipient not receiving duplicate services from insurance, Medicaid, etc.[5]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Administered locally; some grants county-specific (e.g., CareLink limited to Pulaski, Saline, Monroe, Prairie, Lonoke, Faulkner counties).[5]",
    "regional_variations": "Eligibility, services, and providers vary by local Area Agency on Aging and specific grants; contact local agency for details.[1][3][5]",
    "offices_or_providers": ["Local Area Agencies on Aging; Alzheimer's Arkansas for central AR grants (Pulaski etc.).[1][3][5]"]
  },
  "official_source": "https://agingarkansas.org/services/family-caregiver-support/",
  "gotchas": ["Not all grants are identical; each has unique requirements like specific diagnosis or county residency—always check with local Area Agency on Aging.[3][5]", "Services cannot duplicate other funding (e.g., Medicaid, Medicare, private insurance).[5]", "This is distinct from VA or Medicaid paid caregiver programs.[2][4]", "Primarily respite grants, not ongoing paid caregiving.[1]"],
  "data_shape_notes": "Decentralized by local Area Agencies on Aging and grants; no statewide income/asset test; services vary by grant and region (e.g., county-restricted like CareLink); no fixed hours/dollars listed."
}

{
  "name": "Long-term Care Ombudsman",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; available to all residents of long-term care facilities regardless of financial status[5][6]",
    "asset_limits": "No asset limits; no financial tests apply[5][6]",
    "other_requirements": ["Must be a resident of a long-term care facility in Arkansas (e.g., nursing home, assisted living); anyone can contact on behalf of a resident, including family, friends, staff, or anonymously[5][6]"]
  },
  "benefits": {
    "type": "advocacy",
    "value": "Advocacy services including investigating complaints, resolving issues related to resident rights, quality of life, Medicaid/Medicare, discharges/transfers, finances, restraints, guardianship/power of attorney, food quality, room temperature, social activities, care plans; education on rights; empowerment to speak for themselves; no specific dollar amounts or hours, provided as needed without reprisal[5][6]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: Contact local ombudsman (numbers posted in facilities; regional via Area Agency on Aging)[5]", "In-person: Local ombudsman at long-term care facilities", "Anyone can contact: friends, relatives, staff, anonymous callers[5][6]"],
    "processing_time": "Immediate response to concerns; no formal processing timeline specified[5][6]",
    "waitlist": null,
    "forms": ["No specific forms required for receiving services; complaints handled directly[5]"],
    "documents": ["No documents needed to request services; provide details of concern[5][6]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Limited to residents of long-term care facilities across Arkansas; access assured in each service area[4]",
    "regional_variations": "Training varies slightly by region; delivered through local Area Agencies on Aging; different regional ombudsmen and offices[1][3]",
    "offices_or_providers": ["Area Agencies on Aging (AAA) in each region; State Long-Term Care Ombudsman oversees[1][3][4]"]
  },
  "official_source": "https://agingarkansas.org/how-to-become-part-of-the-ombudsman-program-in-arkansas/",
  "gotchas": ["This is not a direct service or financial aid program but free advocacy for long-term care facility residents only—not for home care or non-residents; people often confuse it with becoming a volunteer ombudsman (which has training/age requirements) vs. receiving services (open to all facility residents); must contact local ombudsman posted in facilities, not a central application[1][5][6]", "Volunteers/representatives have strict conflict of interest rules (e.g., no relation to facility staff/residents)[1][2][8]"],
  "data_shape_notes": "no income/asset test; advocacy-only for long-term care facility residents statewide via regional Area Agencies on Aging; anyone can request on behalf of resident; not a qualification/application-based benefit program"
}
